diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..3a7b7e35eabc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1804,9 +1804,58 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     }
   }

+  // Fold unsigned ceiling division pattern:
+  // (lshr X, C) + (zext (icmp ne (X & (2^C - 1)), 0)) --> (X + (2^C - 1)) >> C
+  // This recognizes the pattern: floor(x / 2^C) + (x % 2^C != 0) --> ceil(x / 2^C)
+  {
+    Value *X;
+    const APInt *C;
+    // Match (lshr X, C) on one side
+    if (match(LHS, m_OneUse(m_LShr(m_Value(X), m_APInt(C)))) &&
+        C->ult(X->getType()->getScalarSizeInBits())) {
+      // Match (zext (icmp ne (X & (2^C - 1)), 0)) on the other side
+      const APInt *MaskC;
+      if (match(RHS, m_OneUse(m_ZExt(m_OneUse(m_SpecificICmp(
+              ICmpInst::ICMP_NE, m_OneUse(m_And(m_Specific(X), m_APInt(MaskC))),
+              m_ZeroInt())))))) {
+        // Check that the mask is (2^C - 1)
+        if (*MaskC == (APInt::getOneBitSet(C->getBitWidth(), C->getZExtValue()) -
+                      1)) {
+          // Only fold if we can prove X + (2^C - 1) won't overflow.
+          // We need either NUW on the original add, or we can prove via range info.
+          Constant *AddC = ConstantInt::get(X->getType(), *MaskC);
+          if (I.hasNoUnsignedWrap() ||
+              willNotOverflowUnsignedAdd(X, AddC, I)) {
+            Value *NewAdd = Builder.CreateAdd(X, AddC);
+            Constant *ShiftC = ConstantInt::get(X->getType(), *C);
+            return BinaryOperator::CreateLShr(NewAdd, ShiftC);
+          }
+        }
+      }
+    }
+    // Try the other way around: zext on LHS, lshr on RHS
+    if (match(RHS, m_OneUse(m_LShr(m_Value(X), m_APInt(C)))) &&
+        C->ult(X->getType()->getScalarSizeInBits())) {
+      const APInt *MaskC;
+      if (match(LHS, m_OneUse(m_ZExt(m_OneUse(m_SpecificICmp(
+              ICmpInst::ICMP_NE, m_OneUse(m_And(m_Specific(X), m_APInt(MaskC))),
+              m_ZeroInt())))))) {
+        if (*MaskC == (APInt::getOneBitSet(C->getBitWidth(), C->getZExtValue()) -
+                      1)) {
+          Constant *AddC = ConstantInt::get(X->getType(), *MaskC);
+          if (I.hasNoUnsignedWrap() ||
+              willNotOverflowUnsignedAdd(X, AddC, I)) {
+            Value *NewAdd = Builder.CreateAdd(X, AddC);
+            Constant *ShiftC = ConstantInt::get(X->getType(), *C);
+            return BinaryOperator::CreateLShr(NewAdd, ShiftC);
+          }
+        }
+      }
+    }
+  }
+
   if (Instruction *R = tryFoldInstWithCtpopWithNot(&I))
     return R;
-
   // TODO(jingyue): Consider willNotOverflowSignedAdd and
   // willNotOverflowUnsignedAdd to reduce the number of invocations of
   // computeKnownBits.

